			input.claimToken ?? null,
			JSON.stringify(input.metadata ?? {}),
			JSON.stringify(input.workItemSnapshot ?? {}),
			now,
			now,
		],
	});

	return {
		id,
		status,
		kind: input.kind,
		createdAt: now,
	};
