		toNodeType: "artifact",
		toNodeId: artifactId,
		relation: "posts",
		metadata: {
			origin: "issue-status-comment",
		},
	});
}

async function getArtifactWorkItemId(
	client: Client,
	artifactId: string,
): Promise<string | null> {
	const result = await client.execute({
		sql: `
			SELECT work_item_id
			FROM artifacts
			WHERE id = ?
			LIMIT 1
		`,
		args: [artifactId],
	});

	return (result.rows[0] as { work_item_id?: string } | undefined)?.work_item_id ?? null;
}

